#include <bits/stdc++.h>using namespace std;#define int long long int#define all(x) x.begin(), x.end() void solve() {    int n; cin >> n;    int a[n];    int pos = -1;    for (int i = 0; i < n; i++) {        cin >> a[i];        if (a[i] == n) pos = i;    }     int ans = 0;    for (int j = 0; j < 2; j++) {        vector<int> v;        if (j == 0) for (int i = 0; i <= pos; i++) v.push_back(a[i]);        else for (int i = pos; i < n; i++) v.push_back(a[i]);         int len = v.size();        if (len == 0) continue;        vector<int> L(len), R(len);        stack<int> s;                for (int i = 0; i < len; i++) {            while (!s.empty() and v[i] > s.top()) s.pop();            s.push(v[i]);            L[i] = s.size();        }         while (!s.empty()) s.pop();        for (int i = len - 1; i >= 0; i--) {            while (!s.empty() and v[i] > s.top()) s.pop();            s.push(v[i]);            R[i] = s.size();        }         int mx = 0;        for (int i = 0; i < len; i++) mx = max(mx, L[i] + R[i] - 1);        ans = max(ans, mx);     }    cout << n - ans << '\n';}int32_t main() {    ios_base::sync_with_stdio(0); cin.tie(0);    int t = 1; cin >> t;    while (t--) solve();    return 0;}